  },

  // Sections
  section: {
    marginBottom: 32,
  },
  sectionTitle: {
    fontSize: 11,
    fontWeight: '600',
    color: colors.charcoal.muted,
    letterSpacing: 1.8,
    marginBottom: 16,
    paddingHorizontal: 8,
  },

  // Topic Cards
  topicCard: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: isDarkMode ? colors.paper : '#FFFFFF',
    paddingHorizontal: 20,
    paddingVertical: 18,
    borderRadius: 24,
    marginBottom: 12,
    borderWidth: 1,
    borderColor: colors.ivory.border,
    shadowColor: '#000',
    shadowOffset: {width: 0, height: 4},
    shadowOpacity: 0.02,
    shadowRadius: 15,
    elevation: 2,
  },
  iconContainer: {
    width: 40,
    height: 40,
    borderRadius: 20,
    backgroundColor: colors.ivory.shade,
    alignItems: 'center',
    justifyContent: 'center',
    marginRight: 16,
  },
  topicText: {
    flex: 1,
    fontSize: 16,
    fontWeight: '500',
    color: colors.charcoal.dark,
  },

  // Contact Card
  contactCard: {
    backgroundColor: isDarkMode ? colors.paper : '#FFFFFF',
    borderRadius: 24,
    padding: 32,
    alignItems: 'center',
    borderWidth: 1,
    borderColor: colors.ivory.border,
    shadowColor: '#000',
    shadowOffset: {width: 0, height: 8},
    shadowOpacity: 0.03,
    shadowRadius: 25,
    elevation: 3,
  },
  contactIconContainer: {
    width: 64,
    height: 64,
    borderRadius: 32,
    backgroundColor: isDarkMode ? `${colors.primary.DEFAULT}1A` : `${colors.gold.DEFAULT}10`,
    alignItems: 'center',
    justifyContent: 'center',
    marginBottom: 20,
  },
  contactTitle: {
    fontSize: 18,
    fontWeight: '500',
    color: colors.charcoal.dark,
    marginBottom: 8,
    textAlign: 'center',
  },
  contactDescription: {
    fontSize: 13,
    color: colors.charcoal.muted,
    textAlign: 'center',
    lineHeight: 20,
    marginBottom: 24,
    paddingHorizontal: 16,
  },
  contactButton: {
    paddingVertical: 10,
    paddingHorizontal: 32,
    borderRadius: 24,
    borderWidth: 1,
    borderColor: isDarkMode ? colors.primary.DEFAULT : `${colors.gold.DEFAULT}66`,
    backgroundColor: isDarkMode ? `${colors.primary.DEFAULT}1A` : `${colors.gold.DEFAULT}08`,
  },
  contactButtonText: {
    fontSize: 11,
    fontWeight: '600',
    color: isDarkMode ? colors.primary.DEFAULT : colors.gold.DEFAULT,
    letterSpacing: 1.2,
  },
});

export default HelpSupportScreen;

